# Integrating Prisma with Express

## Introduction

Prisma is a modern ORM for Node.js and TypeScript that provides type-safe database access, automatic migrations, and an intuitive data modeling language. Integrating Prisma with Express gives you a robust, type-safe data layer for your API. This lesson covers setting up Prisma in an Express project, structuring the integration, and implementing common data access patterns.

## Setup

```bash
npm install @prisma/client
npm install -D prisma
npx prisma init
```

This creates a `prisma/` directory with a `schema.prisma` file and a `.env` file.

### Define Your Schema

```prisma
// prisma/schema.prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model User {
  id           Int       @id @default(autoincrement())
  email        String    @unique
  name         String
  passwordHash String    @map("password_hash")
  role         Role      @default(USER)
  posts        Post[]
  createdAt    DateTime  @default(now()) @map("created_at")
  updatedAt    DateTime  @updatedAt @map("updated_at")

  @@map("users")
}

model Post {
  id          Int       @id @default(autoincrement())
  title       String
  content     String
  published   Boolean   @default(false)
  author      User      @relation(fields: [authorId], references: [id])
  authorId    Int       @map("author_id")
  tags        Tag[]
  createdAt   DateTime  @default(now()) @map("created_at")
  updatedAt   DateTime  @updatedAt @map("updated_at")

  @@map("posts")
}

model Tag {
  id    Int    @id @default(autoincrement())
  name  String @unique
  posts Post[]

  @@map("tags")
}

enum Role {
  USER
  ADMIN
  EDITOR
}
```

### Run Migrations

```bash
npx prisma migrate dev --name init
npx prisma generate  # Generate the Prisma Client
```

## Prisma Client Singleton

Create a single Prisma Client instance shared across your application:

```typescript
// src/config/database.ts
import { PrismaClient } from '@prisma/client';

const globalForPrisma = globalThis as unknown as {
  prisma: PrismaClient | undefined;
};

export const prisma = globalForPrisma.prisma ?? new PrismaClient({
  log: process.env.NODE_ENV === 'development'
    ? ['query', 'info', 'warn', 'error']
    : ['error'],
});

if (process.env.NODE_ENV !== 'production') {
  globalForPrisma.prisma = prisma;
}
```

The global assignment prevents creating multiple Prisma Client instances during hot reloading in development.

## Service Layer with Prisma

```typescript
// src/modules/users/users.service.ts
import { prisma } from '../../config/database';
import { Prisma, User } from '@prisma/client';
import bcrypt from 'bcrypt';

// Type for user without sensitive fields
type SafeUser = Omit<User, 'passwordHash'>;

const safeUserSelect = {
  id: true,
  email: true,
  name: true,
  role: true,
  createdAt: true,
  updatedAt: true,
} satisfies Prisma.UserSelect;

export const userService = {
  async findAll(params: {
    page: number;
    limit: number;
    search?: string;
    role?: string;
  }): Promise<{ users: SafeUser[]; total: number }> {
    const { page, limit, search, role } = params;
    const where: Prisma.UserWhereInput = {
      ...(search && {
        OR: [
          { name: { contains: search, mode: 'insensitive' } },
          { email: { contains: search, mode: 'insensitive' } },
        ],
      }),
      ...(role && { role: role as any }),
    };

    const [users, total] = await Promise.all([
      prisma.user.findMany({
        where,
        select: safeUserSelect,
        skip: (page - 1) * limit,
        take: limit,
        orderBy: { createdAt: 'desc' },
      }),
      prisma.user.count({ where }),
    ]);

    return { users, total };
  },

  async findById(id: number): Promise<SafeUser | null> {
    return prisma.user.findUnique({
      where: { id },
      select: safeUserSelect,
    });
  },

  async findByEmail(email: string): Promise<User | null> {
    return prisma.user.findUnique({ where: { email } });
  },

  async create(data: { email: string; name: string; password: string }): Promise<SafeUser> {
    const passwordHash = await bcrypt.hash(data.password, 12);
    return prisma.user.create({
      data: {
        email: data.email,
        name: data.name,
        passwordHash,
      },
      select: safeUserSelect,
    });
  },

  async update(id: number, data: Prisma.UserUpdateInput): Promise<SafeUser> {
    return prisma.user.update({
      where: { id },
      data,
      select: safeUserSelect,
    });
  },

  async delete(id: number): Promise<void> {
    await prisma.user.delete({ where: { id } });
  },
};
```

## Controller Layer

```typescript
// src/modules/users/users.controller.ts
import { Request, Response, NextFunction } from 'express';
import { userService } from './users.service';
import { NotFoundError } from '../../utils/ApiError';

export const usersController = {
  async getAll(req: Request, res: Response, next: NextFunction) {
    try {
      const page = parseInt(req.query.page as string) || 1;
      const limit = Math.min(parseInt(req.query.limit as string) || 20, 100);
      const { users, total } = await userService.findAll({
        page, limit,
        search: req.query.search as string,
        role: req.query.role as string,
      });

      res.json({
        success: true,
        data: users,
        meta: { total, page, limit, totalPages: Math.ceil(total / limit) },
      });
    } catch (error) {
      next(error);
    }
  },

  async getById(req: Request, res: Response, next: NextFunction) {
    try {
      const id = parseInt(req.params.id, 10);
      const user = await userService.findById(id);
      if (!user) throw new NotFoundError('User', id);
      res.json({ success: true, data: user });
    } catch (error) {
      next(error);
    }
  },

  async create(req: Request, res: Response, next: NextFunction) {
    try {
      const user = await userService.create(req.body);
      res.status(201).json({ success: true, data: user });
    } catch (error) {
      if ((error as any).code === 'P2002') {
        return res.status(409).json({ success: false, error: { message: 'Email already exists' } });
      }
      next(error);
    }
  },

  async update(req: Request, res: Response, next: NextFunction) {
    try {
      const id = parseInt(req.params.id, 10);
      const user = await userService.update(id, req.body);
      res.json({ success: true, data: user });
    } catch (error) {
      if ((error as any).code === 'P2025') {
        return next(new NotFoundError('User', req.params.id));
      }
      next(error);
    }
  },

  async remove(req: Request, res: Response, next: NextFunction) {
    try {
      const id = parseInt(req.params.id, 10);
      await userService.delete(id);
      res.status(204).send();
    } catch (error) {
      next(error);
    }
  },
};
```

## Transactions

```typescript
async function createPostWithTags(data: {
  title: string;
  content: string;
  authorId: number;
  tagNames: string[];
}) {
  return prisma.$transaction(async (tx) => {
    // Create or find tags
    const tags = await Promise.all(
      data.tagNames.map(name =>
        tx.tag.upsert({
          where: { name },
          create: { name },
          update: {},
        })
      )
    );

    // Create post with tags
    return tx.post.create({
      data: {
        title: data.title,
        content: data.content,
        authorId: data.authorId,
        tags: { connect: tags.map(t => ({ id: t.id })) },
      },
      include: { tags: true, author: { select: safeUserSelect } },
    });
  });
}
```

## Graceful Shutdown

```typescript
// src/server.ts
import { prisma } from './config/database';

const server = app.listen(config.port, () => {
  console.log(`Server running on port ${config.port}`);
});

async function gracefulShutdown() {
  console.log('Shutting down...');
  server.close();
  await prisma.$disconnect();
  process.exit(0);
}

process.on('SIGTERM', gracefulShutdown);
process.on('SIGINT', gracefulShutdown);
```

## Error Handling for Prisma Errors

```typescript
// src/middleware/prismaErrorHandler.ts
import { Prisma } from '@prisma/client';

export function handlePrismaError(error: unknown): never {
  if (error instanceof Prisma.PrismaClientKnownRequestError) {
    switch (error.code) {
      case 'P2002': // Unique constraint violation
        throw new ApiError(409, `Duplicate value for ${(error.meta?.target as string[])?.join(', ')}`);
      case 'P2025': // Record not found
        throw new ApiError(404, 'Record not found');
      case 'P2003': // Foreign key constraint
        throw new ApiError(400, 'Related record not found');
      default:
        throw new ApiError(500, 'Database error');
    }
  }
  throw error;
}
```

## Common Pitfalls

### Creating Multiple Prisma Clients

```typescript
// WRONG: new client on every import
export function getDb() { return new PrismaClient(); }

// CORRECT: singleton pattern
export const prisma = new PrismaClient();
```

### Not Handling Prisma-Specific Errors

```typescript
// WRONG: generic 500 for all errors
catch (error) { res.status(500).json({ error: 'Server error' }); }

// CORRECT: translate Prisma errors to appropriate HTTP errors
catch (error) {
  if (error.code === 'P2002') return res.status(409).json({ error: 'Duplicate' });
  if (error.code === 'P2025') return res.status(404).json({ error: 'Not found' });
  next(error);
}
```

## Summary

Integrating Prisma with Express gives you type-safe database access with an intuitive API. Use a singleton Prisma Client, organize code into service and controller layers, handle Prisma-specific errors, use transactions for multi-step operations, and disconnect gracefully on shutdown.

3.5.2.body:
# Repository Pattern in Express

## Introduction

The Repository Pattern provides an abstraction layer between your business logic and data access logic. Instead of scattering Prisma queries throughout controllers and services, you encapsulate all data operations in repository classes. This makes your code more testable, swappable, and maintainable.

## Why Use the Repository Pattern?

```
Without Repository Pattern:

  Controller -> Prisma Client (directly)
  - Hard to test (requires database)
  - Hard to switch databases
  - Business logic mixed with data access
  - Prisma API scattered everywhere

With Repository Pattern:

  Controller -> Service -> Repository -> Prisma Client
  - Easy to test (mock the repository)
  - Easy to switch data sources
  - Clear separation of concerns
  - Data access logic in one place
```

## Basic Repository

```typescript
// src/modules/users/users.repository.ts
import { prisma } from '../../config/database';
import { Prisma, User } from '@prisma/client';

export type CreateUserData = {
  email: string;
  name: string;
  passwordHash: string;
};

export type UpdateUserData = Partial<Omit<CreateUserData, 'email'>>;

export type UserFilter = {
  search?: string;
  role?: string;
};

export class UserRepository {
  async findAll(filter: UserFilter, page: number, limit: number) {
    const where = this.buildWhereClause(filter);

    const [data, total] = await Promise.all([
      prisma.user.findMany({
        where,
        skip: (page - 1) * limit,
        take: limit,
        orderBy: { createdAt: 'desc' },
        select: {
          id: true, email: true, name: true, role: true,
          createdAt: true, updatedAt: true,
        },
      }),
      prisma.user.count({ where }),
    ]);

    return { data, total };
  }

  async findById(id: number) {
    return prisma.user.findUnique({
      where: { id },
      select: {
        id: true, email: true, name: true, role: true,
        createdAt: true, updatedAt: true,
      },
    });
  }

  async findByEmail(email: string) {
    return prisma.user.findUnique({ where: { email } });
  }

  async create(data: CreateUserData) {
    return prisma.user.create({
      data,
      select: { id: true, email: true, name: true, role: true, createdAt: true, updatedAt: true },
    });
  }

  async update(id: number, data: UpdateUserData) {
    return prisma.user.update({
      where: { id },
      data,
      select: { id: true, email: true, name: true, role: true, createdAt: true, updatedAt: true },
    });
  }

  async delete(id: number) {
    return prisma.user.delete({ where: { id } });
  }

  async exists(id: number): Promise<boolean> {
    const count = await prisma.user.count({ where: { id } });
    return count > 0;
  }

  private buildWhereClause(filter: UserFilter): Prisma.UserWhereInput {
    const where: Prisma.UserWhereInput = {};

    if (filter.search) {
      where.OR = [
        { name: { contains: filter.search, mode: 'insensitive' } },
        { email: { contains: filter.search, mode: 'insensitive' } },
      ];
    }

    if (filter.role) {
      where.role = filter.role as any;
    }

    return where;
  }
}

export const userRepository = new UserRepository();
```

## Interface-Based Repository (For Testability)

```typescript
// src/modules/users/users.repository.interface.ts
export interface IUserRepository {
  findAll(filter: UserFilter, page: number, limit: number): Promise<{ data: SafeUser[]; total: number }>;
  findById(id: number): Promise<SafeUser | null>;
  findByEmail(email: string): Promise<User | null>;
  create(data: CreateUserData): Promise<SafeUser>;
  update(id: number, data: UpdateUserData): Promise<SafeUser>;
  delete(id: number): Promise<void>;
  exists(id: number): Promise<boolean>;
}

// Real implementation
export class PrismaUserRepository implements IUserRepository {
  // ... same as above
}

// Test implementation
export class InMemoryUserRepository implements IUserRepository {
  private users: User[] = [];
  private nextId = 1;

  async findAll(filter: UserFilter, page: number, limit: number) {
    let filtered = [...this.users];
    if (filter.search) {
      const s = filter.search.toLowerCase();
      filtered = filtered.filter(u =>
        u.name.toLowerCase().includes(s) || u.email.toLowerCase().includes(s)
      );
    }
    const total = filtered.length;
    const data = filtered.slice((page - 1) * limit, page * limit);
    return { data: data.map(this.toSafeUser), total };
  }

  async findById(id: number) {
    const user = this.users.find(u => u.id === id);
    return user ? this.toSafeUser(user) : null;
  }

  async create(data: CreateUserData) {
    const user = { id: this.nextId++, ...data, role: 'USER', createdAt: new Date(), updatedAt: new Date() } as User;
    this.users.push(user);
    return this.toSafeUser(user);
  }

  // ... other methods
}
```

## Service Layer Using Repository

```typescript
// src/modules/users/users.service.ts
import { IUserRepository } from './users.repository.interface';
import { userRepository } from './users.repository';
import bcrypt from 'bcrypt';
import { ConflictError, NotFoundError } from '../../utils/ApiError';

export class UserService {
  constructor(private repo: IUserRepository = userRepository) {}

  async getUsers(filter: UserFilter, page: number, limit: number) {
    return this.repo.findAll(filter, page, limit);
  }

  async getUserById(id: number) {
    const user = await this.repo.findById(id);
    if (!user) throw new NotFoundError('User', id);
    return user;
  }

  async createUser(data: { email: string; name: string; password: string }) {
    const existing = await this.repo.findByEmail(data.email);
    if (existing) throw new ConflictError('Email already registered');

    const passwordHash = await bcrypt.hash(data.password, 12);
    return this.repo.create({ email: data.email, name: data.name, passwordHash });
  }

  async updateUser(id: number, data: UpdateUserData) {
    if (!(await this.repo.exists(id))) {
      throw new NotFoundError('User', id);
    }
    return this.repo.update(id, data);
  }

  async deleteUser(id: number) {
    if (!(await this.repo.exists(id))) {
      throw new NotFoundError('User', id);
    }
    await this.repo.delete(id);
  }
}

export const userService = new UserService();
```

## Testing with Mock Repository

```typescript
// src/modules/users/__tests__/users.service.test.ts
import { describe, it, expect, beforeEach } from 'vitest';
import { UserService } from '../users.service';
import { InMemoryUserRepository } from '../users.repository.memory';

describe('UserService', () => {
  let service: UserService;
  let repo: InMemoryUserRepository;

  beforeEach(() => {
    repo = new InMemoryUserRepository();
    service = new UserService(repo);
  });

  it('should create a user', async () => {
    const user = await service.createUser({
      email: 'alice@example.com',
      name: 'Alice',
      password: 'password123',
    });

    expect(user.email).toBe('alice@example.com');
    expect(user.name).toBe('Alice');
    expect(user).not.toHaveProperty('passwordHash');
  });

  it('should throw ConflictError for duplicate email', async () => {
    await service.createUser({ email: 'alice@example.com', name: 'Alice', password: 'pass123' });
    await expect(
      service.createUser({ email: 'alice@example.com', name: 'Bob', password: 'pass456' })
    ).rejects.toThrow('Email already registered');
  });

  it('should throw NotFoundError for missing user', async () => {
    await expect(service.getUserById(999)).rejects.toThrow('User with ID 999 not found');
  });
});
```

## Generic Base Repository

```typescript
// src/utils/BaseRepository.ts
export interface PaginatedResult<T> {
  data: T[];
  total: number;
}

export interface BaseRepository<T, CreateData, UpdateData> {
  findAll(page: number, limit: number): Promise<PaginatedResult<T>>;
  findById(id: number): Promise<T | null>;
  create(data: CreateData): Promise<T>;
  update(id: number, data: UpdateData): Promise<T>;
  delete(id: number): Promise<void>;
  exists(id: number): Promise<boolean>;
}
```

## When to Use the Repository Pattern

```
USE when:
  - You want to test business logic without a database
  - You might switch databases or ORMs
  - You have complex query logic that benefits from encapsulation
  - Your team values clear architectural boundaries

SKIP when:
  - Small project / prototype
  - Prisma is tightly coupled and you will not switch
  - The extra abstraction layer adds unnecessary complexity
  - YAGNI (You Aren't Gonna Need It)
```

## Summary

The Repository Pattern abstracts data access behind an interface. This separates concerns, improves testability (inject mock repositories), and centralizes query logic. Use interface-based repositories when you need flexibility, or concrete repositories for simpler apps. The pattern shines in larger applications with complex business logic that needs thorough testing.

