# Project Setup: Blog API with Auth and CRUD

## Introduction

In this project lesson, you will build a complete Blog API from scratch. This is not a toy — it is a production-grade REST API with authentication, authorization, full CRUD for posts and comments, and proper error handling. By the end, you will have a working API that demonstrates everything from the Express fundamentals module.

## Project Architecture

```
blog-api/
  prisma/
    schema.prisma
    migrations/
  src/
    config/
      index.ts          # Environment config with Zod validation
      database.ts       # Prisma client singleton
      passport.ts       # Passport strategies
    middleware/
      authenticate.ts   # JWT auth middleware
      authorize.ts      # Role-based authorization
      validate.ts       # Zod validation middleware
      errorHandler.ts   # Global error handler
    modules/
      auth/
        auth.routes.ts
        auth.controller.ts
        auth.service.ts
        auth.schemas.ts
      users/
        users.routes.ts
        users.controller.ts
        users.service.ts
        users.repository.ts
        users.schemas.ts
      posts/
        posts.routes.ts
        posts.controller.ts
        posts.service.ts
        posts.repository.ts
        posts.schemas.ts
      comments/
        comments.routes.ts
        comments.controller.ts
        comments.service.ts
        comments.schemas.ts
    utils/
      ApiError.ts
      asyncHandler.ts
    app.ts
    server.ts
  .env
  .env.example
  package.json
  tsconfig.json
```

## Step 1: Database Schema

```prisma
// prisma/schema.prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model User {
  id           Int       @id @default(autoincrement())
  email        String    @unique
  name         String
  passwordHash String    @map("password_hash")
  role         Role      @default(USER)
  bio          String?
  avatar       String?
  posts        Post[]
  comments     Comment[]
  createdAt    DateTime  @default(now()) @map("created_at")
  updatedAt    DateTime  @updatedAt @map("updated_at")
  @@map("users")
}

model Post {
  id          Int       @id @default(autoincrement())
  title       String
  slug        String    @unique
  content     String
  excerpt     String?
  published   Boolean   @default(false)
  author      User      @relation(fields: [authorId], references: [id])
  authorId    Int       @map("author_id")
  comments    Comment[]
  tags        Tag[]
  publishedAt DateTime? @map("published_at")
  createdAt   DateTime  @default(now()) @map("created_at")
  updatedAt   DateTime  @updatedAt @map("updated_at")
  @@map("posts")
}

model Comment {
  id        Int      @id @default(autoincrement())
  content   String
  post      Post     @relation(fields: [postId], references: [id], onDelete: Cascade)
  postId    Int      @map("post_id")
  author    User     @relation(fields: [authorId], references: [id])
  authorId  Int      @map("author_id")
  createdAt DateTime @default(now()) @map("created_at")
  updatedAt DateTime @updatedAt @map("updated_at")
  @@map("comments")
}

model Tag {
  id    Int    @id @default(autoincrement())
  name  String @unique
  posts Post[]
  @@map("tags")
}

enum Role {
  USER
  ADMIN
  EDITOR
}
```

## Step 2: Auth Module

```typescript
// src/modules/auth/auth.schemas.ts
import { z } from 'zod';

export const registerSchema = z.object({
  body: z.object({
    email: z.string().email(),
    password: z.string().min(8).regex(/[A-Z]/, 'Must contain uppercase').regex(/[0-9]/, 'Must contain number'),
    name: z.string().min(2).max(100),
  }),
});

export const loginSchema = z.object({
  body: z.object({
    email: z.string().email(),
    password: z.string().min(1),
  }),
});
```

```typescript
// src/modules/auth/auth.service.ts
import bcrypt from 'bcrypt';
import { prisma } from '../../config/database';
import { tokenService } from './token.service';
import { ConflictError, UnauthorizedError } from '../../utils/ApiError';

export const authService = {
  async register(data: { email: string; password: string; name: string }) {
    const existing = await prisma.user.findUnique({ where: { email: data.email } });
    if (existing) throw new ConflictError('Email already registered');

    const passwordHash = await bcrypt.hash(data.password, 12);
    const user = await prisma.user.create({
      data: { email: data.email, name: data.name, passwordHash },
      select: { id: true, email: true, name: true, role: true },
    });

    const tokens = tokenService.generateTokenPair({
      userId: user.id, email: user.email, role: user.role,
    });

    return { user, ...tokens };
  },

  async login(email: string, password: string) {
    const user = await prisma.user.findUnique({ where: { email } });
    if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
      throw new UnauthorizedError('Invalid email or password');
    }

    const tokens = tokenService.generateTokenPair({
      userId: user.id, email: user.email, role: user.role,
    });

    return {
      user: { id: user.id, email: user.email, name: user.name, role: user.role },
      ...tokens,
    };
  },
};
```

```typescript
// src/modules/auth/auth.routes.ts
import { Router } from 'express';
import { validate } from '../../middleware/validate';
import { asyncHandler } from '../../utils/asyncHandler';
import { authService } from './auth.service';
import { registerSchema, loginSchema } from './auth.schemas';
import { authenticate } from '../../middleware/authenticate';

const router = Router();

router.post('/register', validate(registerSchema), asyncHandler(async (req, res) => {
  const result = await authService.register(req.body);
  res.status(201).json({ success: true, data: result });
}));

router.post('/login', validate(loginSchema), asyncHandler(async (req, res) => {
  const result = await authService.login(req.body.email, req.body.password);
  res.json({ success: true, data: result });
}));

router.get('/me', authenticate, asyncHandler(async (req, res) => {
  res.json({ success: true, data: req.user });
}));

export default router;
```

## Step 3: Posts Module

```typescript
// src/modules/posts/posts.service.ts (key methods)
import { prisma } from '../../config/database';
import { NotFoundError, ForbiddenError } from '../../utils/ApiError';

function generateSlug(title: string): string {
  return title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '')
    + '-' + Date.now().toString(36);
}

export const postService = {
  async findAll(params: { page: number; limit: number; tag?: string; published?: boolean; authorId?: number }) {
    const { page, limit, tag, published, authorId } = params;
    const where: any = {};
    if (published !== undefined) where.published = published;
    if (authorId) where.authorId = authorId;
    if (tag) where.tags = { some: { name: tag } };

    const [data, total] = await Promise.all([
      prisma.post.findMany({
        where,
        include: {
          author: { select: { id: true, name: true } },
          tags: { select: { id: true, name: true } },
          _count: { select: { comments: true } },
        },
        skip: (page - 1) * limit,
        take: limit,
        orderBy: { createdAt: 'desc' },
      }),
      prisma.post.count({ where }),
    ]);

    return { data, total, page, limit, totalPages: Math.ceil(total / limit) };
  },

  async create(authorId: number, data: { title: string; content: string; tags?: string[] }) {
    const slug = generateSlug(data.title);
    return prisma.post.create({
      data: {
        title: data.title,
        slug,
        content: data.content,
        excerpt: data.content.slice(0, 200),
        authorId,
        ...(data.tags && {
          tags: {
            connectOrCreate: data.tags.map(name => ({
              where: { name },
              create: { name },
            })),
          },
        }),
      },
      include: { author: { select: { id: true, name: true } }, tags: true },
    });
  },

  async update(postId: number, userId: number, userRole: string, data: any) {
    const post = await prisma.post.findUnique({ where: { id: postId } });
    if (!post) throw new NotFoundError('Post', postId);
    if (post.authorId !== userId && userRole !== 'ADMIN') {
      throw new ForbiddenError('You can only edit your own posts');
    }
    return prisma.post.update({
      where: { id: postId },
      data: { ...data, ...(data.title && { slug: generateSlug(data.title) }) },
      include: { author: { select: { id: true, name: true } }, tags: true },
    });
  },

  async delete(postId: number, userId: number, userRole: string) {
    const post = await prisma.post.findUnique({ where: { id: postId } });
    if (!post) throw new NotFoundError('Post', postId);
    if (post.authorId !== userId && userRole !== 'ADMIN') {
      throw new ForbiddenError('You can only delete your own posts');
    }
    await prisma.post.delete({ where: { id: postId } });
  },
};
```

## Step 4: Wire It All Together

```typescript
// src/app.ts
import express from 'express';
import cors from 'cors';
import helmet from 'helmet';
import morgan from 'morgan';
import authRoutes from './modules/auth/auth.routes';
import userRoutes from './modules/users/users.routes';
import postRoutes from './modules/posts/posts.routes';
import commentRoutes from './modules/comments/comments.routes';
import { errorHandler } from './middleware/errorHandler';

const app = express();

app.use(helmet());
app.use(cors({ origin: process.env.CORS_ORIGIN || '*' }));
app.use(morgan(process.env.NODE_ENV === 'production' ? 'combined' : 'dev'));
app.use(express.json());

app.get('/health', (req, res) => res.json({ status: 'ok' }));

app.use('/api/auth', authRoutes);
app.use('/api/users', userRoutes);
app.use('/api/posts', postRoutes);
app.use('/api/comments', commentRoutes);

app.use((req, res) => res.status(404).json({ error: 'Route not found' }));
app.use(errorHandler);

export default app;
```

## API Endpoints Summary

```
Auth:
  POST   /api/auth/register     - Register new user
  POST   /api/auth/login        - Login, get tokens
  GET    /api/auth/me           - Get current user (auth required)

Posts:
  GET    /api/posts             - List posts (public, with pagination)
  GET    /api/posts/:id         - Get single post (public)
  POST   /api/posts             - Create post (auth required)
  PATCH  /api/posts/:id         - Update post (author or admin)
  DELETE /api/posts/:id         - Delete post (author or admin)

Comments:
  GET    /api/posts/:postId/comments  - List comments
  POST   /api/posts/:postId/comments  - Create comment (auth)
  DELETE /api/comments/:id            - Delete comment (author or admin)

Users:
  GET    /api/users             - List users (admin only)
  GET    /api/users/:id         - Get user profile (public)
  PATCH  /api/users/:id         - Update user (self or admin)
```

## Common Pitfalls

### Not Checking Ownership

Always verify that the authenticated user owns the resource they are trying to modify, or has admin privileges.

### Exposing Password Hashes

Always use `select` to exclude passwordHash from query results. Never return it in API responses.

## Summary

This project brings together Express fundamentals, middleware, authentication, validation, and Prisma integration into a cohesive, production-quality API. The feature-based structure keeps code organized, custom error classes ensure consistent responses, and JWT authentication secures protected endpoints.

